  move_mode_desc: { en: 'Move Mode - Move strands and control points around the canvas', fr: 'Mode Déplacer - Déplace les brins et points de contrôle sur le canevas', de: 'Bewegen-Modus - Bewegt Stränge und Kontrollpunkte auf der Leinwand', it: 'Modalità Sposta - Sposta fili e punti di controllo sul canvas', es: 'Modo Mover - Mueve cordones y puntos de control en el lienzo', pt: 'Modo Mover - Move mechas e pontos de controle na tela', he: 'מצב הזזה - מזיז חוטים ונקודות בקרה על הקנווס' },
  rotate_mode_desc: { en: 'Rotate Mode - Rotate selected strands', fr: 'Mode Pivoter - Fait pivoter les brins sélectionnés', de: 'Drehen-Modus - Dreht ausgewählte Stränge', it: 'Modalità Ruota - Ruota i fili selezionati', es: 'Modo Rotar - Rota los cordones seleccionados', pt: 'Modo Girar - Gira as mechas selecionadas', he: 'מצב סיבוב - מסובב חוטים נבחרים' },
  toggle_grid_desc: { en: 'Toggle Grid - Show/hide the grid on the canvas', fr: 'Basculer Grille - Affiche/masque la grille sur le canevas', de: 'Raster umschalten - Raster auf der Leinwand anzeigen/ausblenden', it: 'Attiva/Disattiva Griglia - Mostra/nasconde la griglia sul canvas', es: 'Alternar Cuadrícula - Muestra/oculta la cuadrícula en el lienzo', pt: 'Alternar Grade - Mostra/oculta a grade na tela', he: 'החלף רשת - מציג/מסתיר את הרשת על הקנווס' },
  angle_adjust_desc: { en: 'Angle Adjust Mode - Fine-tune the angles of strand connections', fr: 'Mode Ajustement Angle - Affine les angles des connexions de brins', de: 'Winkel anpassen - Feinjustierung der Winkel von Strangverbindungen', it: 'Modalità Regola Angolo - Regola finemente gli angoli delle connessioni dei fili', es: 'Modo Ajustar Ángulo - Ajusta finamente los ángulos de las conexiones de cordones', pt: 'Modo Ajustar Ângulo - Ajusta finamente os ângulos das conexões das mechas', he: 'מצב התאמת זווית - מכוונן במדויק זוויות של חיבורי חוטים' },
