  select_strand_desc: { en: 'Select Strand - Enter selection mode to select strands', fr: 'Sélectionner Brin - Active le mode sélection pour sélectionner les brins', de: 'Strang auswählen - Aktiviert den Auswahlmodus zum Auswählen von Strängen', it: 'Seleziona Filo - Attiva la modalità selezione per selezionare i fili', es: 'Seleccionar Cordón - Activa el modo selección para seleccionar cordones', pt: 'Selecionar Mecha - Ativa o modo de seleção para selecionar mechas', he: 'בחר חוט - מפעיל מצב בחירה לבחירת חוטים' },
  mask_mode_desc: { en: 'Mask Mode - Hide parts of strands that pass under others', fr: `Mode Masque - Masque les parties de brins qui passent sous d'autres`, de: 'Maskenmodus - Blendet Teile von Strängen aus, die unter anderen verlaufen', it: 'Modalità Maschera - Nasconde parti di fili che passano sotto altri', es: 'Modo Máscara - Oculta partes de cordones que pasan por debajo de otros', pt: 'Modo Máscara - Oculta partes de mechas que passam por baixo de outras', he: 'מצב מסכה - מסתיר חלקים של חוטים העוברים מתחת לאחרים' },
