  toggle_shadow_desc: { en: 'Toggle Shadow - Show/hide shadows on strands', fr: 'Basculer Ombre - Affiche/masque les ombres sur les brins', de: 'Schatten ein/aus - Zeigt/verbirgt Schatten auf Strängen', it: 'Attiva/Disattiva Ombra - Mostra/nasconde le ombre sui fili', es: 'Alternar Sombra - Muestra/oculta sombras en los cordones', pt: 'Alternar Sombra - Mostra/oculta sombras nas mechas', he: 'החלף צל - מציג/מסתיר צללים על חוטים' },
