  rotate_group_desc: { en: 'Rotate Group - Rotate all strands in the group', fr: 'Tourner Groupe - Fait pivoter tous les brins du groupe', de: 'Gruppe drehen - Alle Stränge der Gruppe drehen', it: 'Ruota Gruppo - Ruota tutti i fili del gruppo', es: 'Rotar Grupo - Rota todos los cordones del grupo', pt: 'Rotacionar Grupo - Rotaciona todas as mechas do grupo', he: 'סובב קבוצה - מסובב את כל החוטים בקבוצה' },
  edit_strand_angles_desc: { en: 'Edit Strand Angles - Aligns all strand angles in the group to be parallel with a single click', fr: `Éditer Angles des Brins - Aligne tous les angles des brins du groupe pour qu'ils soient parallèles en un clic`, de: 'Strangwinkel bearbeiten - Alle Strangwinkel der Gruppe parallel ausrichten', it: 'Modifica Angoli dei Fili - Allinea tutti gli angoli dei fili nel gruppo per renderli paralleli con un solo clic', es: 'Editar Ángulos de Cordones - Alinea todos los ángulos de los cordones del grupo para que sean paralelos con un solo clic', pt: 'Editar Ângulos das Mechas - Alinha todos os ângulos das mechas do grupo para ficarem paralelos com um único clique', he: 'ערוך זוויות חוטים - מיישר את כל זוויות החוטים בקבוצה כך שיהיו מקבילים זה לזה בלחיצת כפתור' },
