  delete_group_desc: { en: 'Delete Group - Remove this group (strands remain)', fr: 'Supprimer Groupe - Supprime ce groupe (les brins restent)', de: 'Gruppe löschen - Diese Gruppe entfernen (Stränge bleiben)', it: 'Elimina Gruppo - Rimuove questo gruppo (i fili rimangono)', es: 'Eliminar Grupo - Elimina este grupo (los cordones permanecen)', pt: 'Excluir Grupo - Remove este grupo (as mechas permanecem)', he: 'מחק קבוצה - מסיר את הקבוצה הזו (החוטים נשארים)' },
