  triangle_control_name: { en: `Triangle (Green with strand's color center)`, fr: 'Triangle (Vert avec centre de couleur du brin)', de: 'Dreieck (Grün mit Strangfarbe in der Mitte)', it: 'Triangolo (Verde con centro del colore del filo)', es: 'Triángulo (Verde con centro del color del cordón)', pt: 'Triângulo (Verde com centro da cor da mecha)', he: 'משולש (ירוק עם מרכז בצבע החוט)' },
